var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"예─이! 다들 잘 지냈어?","JPN":"イェーイ！　みんな元気してる？","ENG":"EYYYY! How's everyone doing?","TWN":"哈～囉！大家好！"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"언제나 여러분을 초 하이 텐션으로 가이드해 주는 건틀렛의 요정, 베티 미치야!","JPN":"毎回皆さんを超ハイテンションにガイドするガントレットの妖精、ベティー・ミッチーだよ！","ENG":"Batty Mitchie here, the Gauntlet fairy, and your guide to a hyper-active time!","TWN":"我是不管什麼時候都熱情替觀眾報導的聖鎧精靈，貝蒂·米琪！"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"지금 우리가 있는 여기는 바로 샤레이드 상공! 엄청나! 화려해! 멋져!","JPN":"今私たちがいるここは、シャレードの上空！　すごい！　派手！　カッコいい！","ENG":"We are currently flying over the skies of Charade! Amazing! Cool! Rad!","TWN":"現在我們所在的位置是非常！華美！帥氣！的查雷德上空！"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"하. 지. 만☆ 잠시 후면 이 도시는 불바다가 된다!","JPN":"で・も☆もうすぐこの街は火の海になるぞ！","ENG":"How. Ev. Er...☆ It won't be long until this city turns itself into the fiery pits of hell!","TWN":"但，是，呢☆只要再過一會兒這座城市就會陷入一片火海！"},"stage":{"bg":"HELI_NORMAL","slots":{"L":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"샤레이드 건틀렛 리그! 태스크포스들끼리 치고 받는다는데 싫어할 사람 누구 있어~?","JPN":"シャレードガントレットリーグ！　タスクフォース同士で戦うっていうのに、イヤって人いる～？","ENG":"The Charade Gauntlet League! Who doesn't like the idea of TASKFORCEs fighting each other?","TWN":"查雷德聖鎧聯賽！說到特遣勢力之間的角力，有誰會不喜歡呢～？"},"stage":{"bg":"HELI_NORMAL","slots":{"L":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"이번 시즌 슈퍼 루키는 누굴까? 화약 냄새 찡한 경기장을 불태울 염문설의 주인공은 과연?","JPN":"今シーズンのスーパールーキーは誰か？　火薬の匂いに溢れる競技場を燃やす、スキャンダルの主人公は？","ENG":"Who will be the super rookie of the season? Who's the mystery star that heated up the gunpowder-filled stadium with a hot scandal?","TWN":"誰將成為本賽季的超級新秀？在賽場上點燃戰火的主角究竟會是誰？"},"stage":{"bg":"HELI_NORMAL","slots":{"L":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"뭣보다 엄마 젖이나 더 먹고 와야 할 최고의 꼴불견들도 빼놓을 수 없. 겠. 지?","JPN":"何より、まだまだママのおっぱいが必要なイカすベイビーたちのみっともない姿も、見・の・が・せ・ない！","ENG":"And of course, we can't forget about the worst losers who\xA0were born yesterday, can we?","TWN":"當然也不能錯過毛還沒長齊就來的最佳菜鳥選手，是，吧？"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"이 밋치미치랑 함께 구경하면서 즐겁게 비웃어 주자구~","JPN":"このミッチーミッチーと一緒に見物しながら、楽しく笑ってやろう～","ENG":"Let's mock the heck out of them together, with Mitchie-Mitchie!","TWN":"還是回家找媽媽喝奶去吧！從現在開始，和米琪一起歡呼，一起盡情地嘲諷吧～"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"안전 벨트 꽉 매시라! 놀라서 지려도 이 언니는 책임 안 질 테니까!","JPN":"シートベルトしっかり締めてね！　ビックリして漏らしても、お姉さんは知らないよ！","ENG":"Y'all folks better fasten your seat belts, because this is gonna be one hell of a ride.","TWN":"系好安全帶！萬一嚇到尿褲子米琪可不負責喔！"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>알파트릭스 일렉트로닉스와 함께하는 이번 시즌! 베팅은 공식 홈페이지에서만 가능합니다!</color>","JPN":"<color=#ffd34c>アルファトリックス・エレクトロニクスが公式スポンサーとなっている今シーズン！　ベットは公式ホームページでのみ可能となっています！</color>","ENG":"<color=#ffd34c>This season is sponsored by Alphatrix Electronics! Bets are available through the official website only!</color>","TWN":"<color=#ffd34c>本賽季由阿爾法崔克斯電子贊助播出！前往官網為你喜歡的隊伍下注吧！</color>"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"……뭐라고 떠드는 건지 하나도 모르겠네.","JPN":"……何を言ってるのかさっぱりわからないや。","ENG":"...I didn't get a single word of what she said.","TWN":"……我完全聽不懂她在說什麼。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"걔 방송은 추천 안 해. 샤레이드에서 밋치보다 영양가 없는 리포터도 드물어.","JPN":"あの子の番組はおすすめしないよ。シャレードでミッチーほど足しにならないレポーターもそうそういないわ。","ENG":"Don't watch her show. It's hard to find someone more vulgar than Mitchie in Charade.","TWN":"我不推薦你聽她的節目。她是查雷德最沒營養的主播。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"그러고 보니 미나는 건틀렛 리그에 나가 본 적 없다고 했지?","JPN":"そういえば、ミナはガントレットリーグに出たことないって言ってたよね？","ENG":"Come to think of it, you've never played in the Gauntlet League, Mina. Am I right?","TWN":"話說，米娜你說你從來沒參加過聖鎧聯賽是吧？"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"아, 응. 모의전은 다른 소대랑 몇 번 하긴 했지만.","JPN":"あ、うん。模擬戦なら他の小隊と何度かやったことはあるけど。","ENG":"Oh, yeah. I tried a few mock battles with other squads.","TWN":"嗯，對，不過是和其他小隊進行過幾次模擬戰。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"규칙은 간단해. 공격 측은 수비측 거점을 점령하면 승리.","JPN":"ルールは簡単よ。攻撃側が守備側の拠点を占領すれば勝ちなの。","ENG":"The rules are simple. The offensive team wins by capturing the defensive team's base.","TWN":"規則很簡單。進攻的一方佔領防守方的據點就算獲勝。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"수비측은 제한 시간 동안 거점을 지키거나 공격측 거점을 점령하면 승리.","JPN":"守備側は制限時間内に拠点を守り切るか、攻撃側の拠点を占領すれば勝ち。","ENG":"The defensive team wins by either protecting their base during a set time, or capturing the offensive team's base.","TWN":"相反的，防守方在規定時間內守住據點，或者佔領進攻方的據點就算獲勝。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};